import Footer from '../components/Footer';
import WhatsAppBtn from '../components/WhatsAppBtn';

export default function MainLayout({ children }) {
  return (
    <>
      <Navbar />
      <main>{children}</main>
      <Footer />
      <WhatsAppBtn />
    </>
  );
}
